import { Injectable } from '@angular/core';
import { HttpEvent, HttpHandler, HttpInterceptor, HttpRequest } from '@angular/common/http';
import { Observable } from 'rxjs';
import { AuthService } from '../services/auth.service';
import { ParkaddaAuthService } from '../services/parkadda-auth.service';

@Injectable()
export class AuthInterceptor implements HttpInterceptor {
  constructor(
    private auth: AuthService,
    private parkaddaAuth: ParkaddaAuthService
  ) {}

  intercept(req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
    // Handle Parkadda API requests
    if (req.url.includes('localhost:8080/api')) {
      const parkaddaToken = this.parkaddaAuth.getParkaddaToken();
      if (parkaddaToken) {
        const cloned = req.clone({
          setHeaders: {
            Authorization: `Bearer ${parkaddaToken}`
          }
        });
        return next.handle(cloned);
      }
      return next.handle(req);
    }

    // Handle other API requests with main auth token
    const token = this.auth.getToken();
    if (token) {
      const cloned = req.clone({
        setHeaders: {
          Authorization: `Bearer ${token}`
        }
      });
      return next.handle(cloned);
    }
    return next.handle(req);
  }
}
